import { useState } from "react";

import { NestedConfirmDialog } from "@mormlayer/components/ui/NestedConfirmDialog";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const WARNING_CONTENT = (
  <>
    <p className="nested-confirm-body">
      Runtime status moves from <strong>Online</strong> to{" "}
      <strong>Paused</strong> via an on-chain mandate update for{" "}
      <strong>Alpha Arb</strong>.
    </p>
    <p className="nested-confirm-body terminal-text-muted">
      Active tasks will be halted. Pending intents may be rejected.
    </p>
  </>
);

function NestedConfirmDialogDemo({
  isOpen,
  disabled,
  confirmDisabled,
  onOpenChange,
}: {
  isOpen: boolean;
  disabled: boolean;
  confirmDisabled: boolean;
  onOpenChange: (open: boolean) => void;
}): JSX.Element {
  return (
    <NestedConfirmDialog
      isOpen={isOpen}
      title="Pause this agent?"
      titleId="nested-confirm-demo-title"
      cancelLabel="Cancel"
      confirmLabel="Pause agent"
      confirmClassName="agentroles-status-confirm-btn--danger"
      disabled={disabled}
      confirmDisabled={confirmDisabled}
      autoFocusCancel={false}
      onCancel={() => onOpenChange(false)}
      onConfirm={() => {
        onOpenChange(false);
      }}
    >
      {WARNING_CONTENT}
    </NestedConfirmDialog>
  );
}

export function NestedConfirmDialogPage(): JSX.Element {
  const [isOpen, setIsOpen] = useState(false);
  const [disabled, setDisabled] = useState(false);
  const [confirmDisabled, setConfirmDisabled] = useState(false);

  return (
    <ComponentDocPage
      title="Nested confirm dialog"
      description="Compact confirmation dialog for nested modal flows. Built on the staggered overlay shell with cancel and confirm actions."
    >
      <DocSection
        title="Interactive demo"
        description="Open the dialog and confirm or cancel. Toggle disabled states below."
      >
        <div className="uitest-controls">
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={disabled}
              onChange={(e) => setDisabled(e.target.checked)}
            />
            <span className="uitest-field__label">disabled (both buttons)</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={confirmDisabled}
              onChange={(e) => setConfirmDisabled(e.target.checked)}
            />
            <span className="uitest-field__label">confirmDisabled</span>
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <button
            type="button"
            className="btn btn-primary"
            onClick={() => setIsOpen(true)}
          >
            Open confirm dialog
          </button>
        </PreviewCanvas>
        <NestedConfirmDialogDemo
          isOpen={isOpen}
          disabled={disabled}
          confirmDisabled={confirmDisabled}
          onOpenChange={setIsOpen}
        />
      </DocSection>

      <DocSection
        title="Disabled states"
        description="Both buttons respect disabled; confirm also respects confirmDisabled."
      >
        <VariantGrid columns={2}>
          <VariantTile label="confirmDisabled">
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => {
                setDisabled(false);
                setConfirmDisabled(true);
                setIsOpen(true);
              }}
            >
              Open (confirm disabled)
            </button>
          </VariantTile>
          <VariantTile label="disabled">
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => {
                setDisabled(true);
                setConfirmDisabled(false);
                setIsOpen(true);
              }}
            >
              Open (all disabled)
            </button>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
