import type { ReactNode } from "react";

import { PreviewCanvas } from "./PreviewCanvas";

export interface VariantGridProps {
  children: ReactNode;
  columns?: 2 | 3 | 4;
}

export function VariantGrid({
  children,
  columns = 3,
}: VariantGridProps): JSX.Element {
  return (
    <div
      className="uitest-variant-grid"
      style={{ gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))` }}
    >
      {children}
    </div>
  );
}

export interface VariantTileProps {
  label: string;
  children: ReactNode;
}

export function VariantTile({
  label,
  children,
}: VariantTileProps): JSX.Element {
  return (
    <figure className="uitest-variant-tile">
      <PreviewCanvas minHeight={200}>{children}</PreviewCanvas>
      <figcaption className="uitest-variant-tile__label">{label}</figcaption>
    </figure>
  );
}
