import { useState } from "react";

import { AnimatedCollapse } from "@mormlayer/components/ui/AnimatedCollapse";
import type { AnimatedCollapseTiming } from "@mormlayer/components/ui/AnimatedCollapse";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const SAMPLE_CONTENT = (
  <div
    style={{
      padding: "12px 16px",
      border: "1px solid var(--terminal-border, #2a3a2a)",
      borderRadius: 4,
      background: "var(--terminal-surface, #0d140d)",
    }}
  >
    <p style={{ margin: 0, fontSize: 13 }}>Collapsible panel content</p>
    <p style={{ margin: "8px 0 0", fontSize: 12, opacity: 0.7 }}>
      Height animates open and closed with CSS grid transitions.
    </p>
  </div>
);

export function AnimatedCollapsePage(): JSX.Element {
  const [open, setOpen] = useState(true);
  const [timing, setTiming] = useState<AnimatedCollapseTiming>("normal");

  return (
    <ComponentDocPage
      title="Animated collapse"
      description="Height-animated collapse wrapper using CSS grid. Supports normal and deck timing presets for panel and deck-style reveals."
    >
      <DocSection
        title="Default preview"
        description="Open collapse with sample content on a terminal canvas."
      >
        <PreviewCanvas>
          <AnimatedCollapse open>
            {SAMPLE_CONTENT}
          </AnimatedCollapse>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Toggle open state and switch between normal and deck timing."
      >
        <div className="uitest-controls">
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={open}
              onChange={(e) => setOpen(e.target.checked)}
            />
            <span className="uitest-field__label">Open</span>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Timing</span>
            <select
              className="uitest-input"
              value={timing}
              onChange={(e) => setTiming(e.target.value as AnimatedCollapseTiming)}
            >
              <option value="normal">normal</option>
              <option value="deck">deck</option>
            </select>
          </label>
        </div>
        <PreviewCanvas minHeight={160}>
          <AnimatedCollapse open={open} timing={timing}>
            {SAMPLE_CONTENT}
          </AnimatedCollapse>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Timing presets"
        description="Normal vs deck animation curves — toggle open to compare."
      >
        <VariantGrid columns={2}>
          <VariantTile label="normal">
            <AnimatedCollapse open timing="normal">
              {SAMPLE_CONTENT}
            </AnimatedCollapse>
          </VariantTile>
          <VariantTile label="deck">
            <AnimatedCollapse open timing="deck">
              {SAMPLE_CONTENT}
            </AnimatedCollapse>
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Closed state"
        description="Collapsed panels hide content and block interaction by default."
      >
        <VariantGrid columns={2}>
          <VariantTile label="normal — closed">
            <AnimatedCollapse open={false} timing="normal">
              {SAMPLE_CONTENT}
            </AnimatedCollapse>
          </VariantTile>
          <VariantTile label="deck — closed">
            <AnimatedCollapse open={false} timing="deck">
              {SAMPLE_CONTENT}
            </AnimatedCollapse>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
