export const MORPHEUM_LOGO_VIEWBOX = "0 0 58 35";

export function MorpheumLogoPaths({
  fill = "var(--terminal-brand)",
}: {
  fill?: string;
}): React.JSX.Element {
  return (
    <>
      {MORPHEUM_LOGO_PATHS.map((d) => (
        <path key={d.slice(0, 24)} d={d} fill={fill} />
      ))}
    </>
  );
}

const LOGO_VIEWBOX_WIDTH = 58;
const LOGO_VIEWBOX_HEIGHT = 35;

export type MorpheumLogoProps = React.SVGProps<SVGSVGElement> & {
  /** Fill color for logo paths. Defaults to brand green. */
  fill?: string;
  /** Inner padding in viewBox units. Defaults to 4. */
  padding?: number;
};

export function MorpheumLogo({
  fill = "#C8F5A8",
  width = 58,
  height = 35,
  padding = 10,
  "aria-hidden": ariaHidden = true,
  ...props
}: MorpheumLogoProps): React.JSX.Element {
  const viewBox = [
    -padding,
    -padding,
    LOGO_VIEWBOX_WIDTH + padding * 2,
    LOGO_VIEWBOX_HEIGHT + padding * 2,
  ].join(" ");

  return (
    <svg
      width={width}
      height={height}
      viewBox={viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden={ariaHidden}
      {...props}
    >
      {MORPHEUM_LOGO_PATHS.map((d) => (
        <path key={d.slice(0, 24)} d={d} fill={fill} />
      ))}
    </svg>
  );
}

export default MorpheumLogo;
