import { useState } from "react";

import ModalHeader from "@mormlayer/components/ui/ModalHeader";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

export function ModalHeaderPage(): JSX.Element {
  const [title, setTitle] = useState("Agent settings");
  const [showTrailingBadge, setShowTrailingBadge] = useState(true);
  const [multiline, setMultiline] = useState(false);
  const [showClose, setShowClose] = useState(true);
  const [chrome, setChrome] = useState(true);
  const [closeCount, setCloseCount] = useState(0);

  const trailing = showTrailingBadge ? (
    <span className="terminal-label" style={{ opacity: 0.85 }}>
      Beta
    </span>
  ) : undefined;

  const leading = multiline ? (
    <div>
      <h3 className="terminal-panel-title">{title}</h3>
      <span className="terminal-label" style={{ display: "block", marginTop: 4 }}>
        Configure skills, env vars, and MCP servers
      </span>
    </div>
  ) : undefined;

  return (
    <ComponentDocPage
      title="Modal header"
      description="Shared modal chrome with title or custom leading, trailing actions, optional close control, and multiline alignment."
    >
      <DocSection
        title="Default preview"
        description="Standard header with title and close on a modal shell."
      >
        <PreviewCanvas minHeight={120}>
          <div className="modal-content" style={{ maxWidth: 480, width: "100%" }}>
            <ModalHeader title="Transfer funds" onClose={() => {}} />
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit title, trailing badge, multiline leading, close handler, and chrome padding."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Title</span>
            <input
              className="uitest-input"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
            />
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showTrailingBadge}
              onChange={(e) => setShowTrailingBadge(e.target.checked)}
            />
            <span className="uitest-field__label">Trailing badge</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={multiline}
              onChange={(e) => setMultiline(e.target.checked)}
            />
            <span className="uitest-field__label">Multiline leading</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showClose}
              onChange={(e) => setShowClose(e.target.checked)}
            />
            <span className="uitest-field__label">onClose (close button)</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={chrome}
              onChange={(e) => setChrome(e.target.checked)}
            />
            <span className="uitest-field__label">Chrome (padding + border)</span>
          </label>
        </div>
        <PreviewCanvas minHeight={140}>
          <div className="modal-content" style={{ maxWidth: 480, width: "100%" }}>
            <ModalHeader
              title={multiline ? undefined : title}
              leading={leading}
              trailing={trailing}
              multiline={multiline}
              chrome={chrome}
              onClose={showClose ? () => setCloseCount((count) => count + 1) : undefined}
            />
          </div>
          {showClose ? (
            <p className="uitest-field__label" style={{ marginTop: 12 }}>
              Close clicked: {closeCount} time{closeCount === 1 ? "" : "s"}
            </p>
          ) : null}
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Variants"
        description="Common header configurations across modal surfaces."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Title + close">
            <div className="modal-content" style={{ width: "100%" }}>
              <ModalHeader title="Deploy agent" onClose={() => {}} />
            </div>
          </VariantTile>
          <VariantTile label="Trailing badge">
            <div className="modal-content" style={{ width: "100%" }}>
              <ModalHeader
                title="Vault operate"
                trailing={<span className="terminal-label">Personal</span>}
                onClose={() => {}}
              />
            </div>
          </VariantTile>
          <VariantTile label="Multiline leading">
            <div className="modal-content" style={{ width: "100%" }}>
              <ModalHeader
                multiline
                onClose={() => {}}
                leading={
                  <div>
                    <h3 className="terminal-panel-title">Copy Alpha Arb</h3>
                    <span className="terminal-label">REGIME_ALPHA_V3</span>
                  </div>
                }
              />
            </div>
          </VariantTile>
          <VariantTile label="No chrome">
            <div className="modal-content" style={{ width: "100%" }}>
              <ModalHeader
                title="Inline header"
                chrome={false}
                onClose={() => {}}
              />
            </div>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
