import type { DecorativeCardType } from "../components/ui/decorative-card/decorativeCardTypes";
import type {
  AgentListingStatus,
  AgentPermissionMode,
  TradingAgent,
  TradingAgentStatus,
} from "../store/types";
import {
  getAgentCustodyKind,
  getAgentCustodyKindLabel,
  getAgentRoleLabel,
  truncateAddress,
} from "./agentRoles";
import { resolveAgentAvatarSvgUrlFromIdentity } from "./agentAvatarSvg";
import { PERMISSION_MODE_LABELS } from "./mintAgent";

export type AgentIdentityBadgePresentation = "compact" | "card" | "passport";

export type AgentIdentityCustodyKind = "wallet" | "vault" | "did_only";

export type AgentIdentityDidDisplayMode = AgentIdentityBadgePresentation;

export interface AgentIdentityBadgeIdentityFields {
  displayName: string;
  role: string;
  did: string;
  handle?: string;
  custodyKind?: AgentIdentityCustodyKind;
  versionTag?: string;
  fleetName?: string;
  status?: TradingAgentStatus;
  permissionMode?: AgentPermissionMode;
  listingStatus?: AgentListingStatus;
}

export type BadgeEmblemResolution =
  | { kind: "logo" }
  | { kind: "avatar"; src: string };

const CUSTODY_KIND_LABELS: Record<AgentIdentityCustodyKind, string> = {
  wallet: "Wallet",
  vault: "Vault",
  did_only: "DID only",
};

export function hasTier3Fields(props: AgentIdentityBadgeIdentityFields): boolean {
  return (
    props.fleetName != null ||
    props.status != null ||
    props.permissionMode != null ||
    props.listingStatus != null
  );
}

export function hasTier4Fields(props: AgentIdentityBadgeIdentityFields): boolean {
  return (
    props.handle != null ||
    props.custodyKind != null ||
    props.versionTag != null
  );
}

export function resolvePresentation(
  props: AgentIdentityBadgeIdentityFields,
  explicit?: AgentIdentityBadgePresentation,
): AgentIdentityBadgePresentation {
  if (explicit) return explicit;
  if (hasTier3Fields(props)) return "passport";
  if (hasTier4Fields(props)) return "card";
  return "compact";
}

export function resolveBadgeEmblemSrc(props: {
  did: string;
  listingStatus?: AgentListingStatus;
}): BadgeEmblemResolution {
  if (props.listingStatus === "listed") {
    return { kind: "avatar", src: resolveAgentAvatarSvgUrlFromIdentity(props.did) };
  }
  return { kind: "logo" };
}

export function formatIdentityMetaLine(props: {
  handle?: string;
  versionTag?: string;
  custodyKind?: AgentIdentityCustodyKind;
}): string | null {
  const segments: string[] = [];
  if (props.handle) segments.push(props.handle);
  if (props.versionTag) segments.push(props.versionTag);
  if (props.custodyKind) segments.push(CUSTODY_KIND_LABELS[props.custodyKind]);
  return segments.length > 0 ? segments.join(" · ") : null;
}

export function formatIdentitySubtitleLine(props: {
  role: string;
  custodyKind?: AgentIdentityCustodyKind;
  permissionMode?: AgentPermissionMode;
}): string {
  const segments = [props.role];
  if (props.custodyKind) segments.push(CUSTODY_KIND_LABELS[props.custodyKind]);
  if (props.permissionMode) {
    segments.push(PERMISSION_MODE_LABELS[props.permissionMode]);
  }
  return segments.join(" · ");
}

const DID_TRUNCATE_CHARS: Record<AgentIdentityDidDisplayMode, number> = {
  compact: 6,
  card: 6,
  passport: 10,
};

export function formatDidDisplay(
  did: string,
  mode: AgentIdentityDidDisplayMode,
): string {
  return truncateAddress(did, DID_TRUNCATE_CHARS[mode]);
}

export function formatStatusLabel(status: TradingAgentStatus): string {
  const labels: Record<TradingAgentStatus, string> = {
    active: "Online",
    idle: "Idle",
    paused: "Paused",
  };
  return labels[status];
}

export function resolveIdentityShellType(props: {
  listingStatus?: AgentListingStatus;
  status?: TradingAgentStatus;
  custodyKind?: AgentIdentityCustodyKind;
}): DecorativeCardType {
  if (props.listingStatus === "listed") return "brand-dark";
  if (props.status === "paused") return "gray-dark";
  if (props.status === "idle") return "transparent";
  if (props.custodyKind === "wallet") return "brand-dark";
  if (props.custodyKind === "vault") return "salmon-strip";
  return "gray-light";
}

export function buildIdentityAriaLabel(
  props: AgentIdentityBadgeIdentityFields,
): string {
  const parts = [props.displayName, props.role];
  if (props.fleetName) parts.push(`in ${props.fleetName}`);
  if (props.status) parts.push(formatStatusLabel(props.status));
  parts.push(`KYA ${formatDidDisplay(props.did, "compact")}`);
  return parts.join(", ");
}

export interface AgentIdentityBadgeBuiltProps extends AgentIdentityBadgeIdentityFields {
  presentation?: AgentIdentityBadgePresentation;
  type?: DecorativeCardType;
  width?: number;
  className?: string;
}

export function buildAgentIdentityBadgeProps(
  agent: TradingAgent,
  fleetName?: string,
): AgentIdentityBadgeBuiltProps {
  return {
    displayName: agent.displayName,
    role: getAgentRoleLabel(agent.role),
    did: agent.did,
    handle: agent.handle,
    versionTag: agent.versionTag,
    custodyKind: getAgentCustodyKind(agent),
    fleetName,
    status: agent.status,
    permissionMode: agent.permissionMode,
    listingStatus: agent.listingStatus,
  };
}

export function getCustodyKindLabel(kind: AgentIdentityCustodyKind): string {
  return CUSTODY_KIND_LABELS[kind];
}

export { getAgentCustodyKindLabel };
