import React, { type JSX } from "react";
import { MorpheumLogoPaths, MORPHEUM_LOGO_VIEWBOX } from "./MorpheumLogo";
import { useMatrixText } from "./useMatrixText";
import "./morpheum-loading.css";

export interface MorpheumInlineLoadingProps {
  message?: string;
  matrixText?: boolean;
}

export function MorpheumInlineLoading({
  message = "Loading...",
  matrixText = true,
}: MorpheumInlineLoadingProps): JSX.Element {
  const displayMessage = useMatrixText(message, matrixText);

  return (
    <div className="message loading morpheum-loading-inline" role="status" aria-live="polite">
      <svg
        className="morpheum-loading-logo"
        viewBox={MORPHEUM_LOGO_VIEWBOX}
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <g className="morpheum-loading-logo__ghost">
          <MorpheumLogoPaths fill="#C8F5A8" />
        </g>
        <g className="morpheum-loading-logo__fill">
          <MorpheumLogoPaths fill="#C8F5A8" />
        </g>
      </svg>
      <span
        className={[
          "morpheum-loading-label",
          "terminal-label",
          matrixText ? "morpheum-loading-label--matrix" : "",
        ]
          .filter(Boolean)
          .join(" ")}
        aria-label={message}
      >
        {displayMessage}
      </span>
    </div>
  );
}

export default MorpheumInlineLoading;
