/** Default mock id length — enough entropy for catalog KPI slice fields (through index 57). */
const MOCK_ID_HEX_LEN = 32;
const SEGMENTS = MOCK_ID_HEX_LEN / 8;

function fnv1a32(input: string): number {
  let hash = 2166136261;
  for (let i = 0; i < input.length; i += 1) {
    hash ^= input.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

/** Stable 32-char lowercase hex mock ID. */
export function mockHashId(seed: string): string {
  const parts: string[] = [];
  for (let round = 0; round < SEGMENTS; round += 1) {
    parts.push(fnv1a32(`${seed}:${round}`).toString(16).padStart(8, "0"));
  }
  const id = parts.join("");
  if (id.length !== MOCK_ID_HEX_LEN) {
    throw new Error(`mockHashId produced invalid length: ${id.length}`);
  }
  return id;
}
