import { useState } from "react";

import { Typewriter } from "@mormlayer/components/ui/Typewriter";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const DEFAULT_TEXT =
  "Autonomous agents monitor regime shifts and surface high-confidence trade intents for your review.";

type MultilineMode = "auto" | "true" | "false";

function parseMultiline(mode: MultilineMode): "auto" | boolean {
  if (mode === "auto") return "auto";
  return mode === "true";
}

export function TypewriterPage(): JSX.Element {
  const [text, setText] = useState(DEFAULT_TEXT);
  const [speed, setSpeed] = useState(40);
  const [active, setActive] = useState(true);
  const [multiline, setMultiline] = useState<MultilineMode>("auto");
  const [restartKey, setRestartKey] = useState(0);

  const multilineProp = parseMultiline(multiline);

  return (
    <ComponentDocPage
      title="Typewriter"
      description="Character-by-character reveal with optional multiline wrapping, cursor hold, and pause/resume via the active prop."
    >
      <DocSection
        title="Default preview"
        description="Auto multiline typing on a terminal canvas."
      >
        <PreviewCanvas>
          <Typewriter text={DEFAULT_TEXT} />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit text, speed, active state, and multiline mode — restart to replay the animation."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Text</span>
            <textarea
              className="uitest-input"
              rows={3}
              value={text}
              onChange={(e) => setText(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Speed ({speed} chars/s)</span>
            <input
              className="uitest-input"
              type="range"
              min={10}
              max={120}
              step={5}
              value={speed}
              onChange={(e) => setSpeed(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={active}
              onChange={(e) => setActive(e.target.checked)}
            />
            <span className="uitest-field__label">Active (typing)</span>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Multiline</span>
            <select
              className="uitest-input"
              value={multiline}
              onChange={(e) => setMultiline(e.target.value as MultilineMode)}
            >
              <option value="auto">auto</option>
              <option value="true">true</option>
              <option value="false">false</option>
            </select>
          </label>
          <button
            type="button"
            className="uitest-input"
            onClick={() => setRestartKey((key) => key + 1)}
          >
            Restart animation
          </button>
        </div>
        <PreviewCanvas minHeight={160}>
          <div style={{ maxWidth: 420, width: "100%" }}>
            <Typewriter
              key={restartKey}
              text={text}
              speed={speed}
              active={active}
              multiline={multilineProp}
            />
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Speed samples"
        description="Same copy at slow, default, and fast reveal rates."
      >
        <VariantGrid columns={3}>
          <VariantTile label="20 chars/s">
            <Typewriter text="Slow reveal for emphasis." speed={20} />
          </VariantTile>
          <VariantTile label="40 chars/s (default)">
            <Typewriter text="Default terminal typing speed." speed={40} />
          </VariantTile>
          <VariantTile label="80 chars/s">
            <Typewriter text="Fast scan-friendly reveal." speed={80} />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
