import React from "react";

import {
  OVERLAY_TIMING,
  StaggeredOverlayBackdrop,
  StaggeredOverlayPanel,
  StaggeredOverlayRoot,
  useStaggeredOverlay,
} from "./overlay";
import "./nestedConfirmDialog.css";

export interface NestedConfirmDialogProps {
  isOpen: boolean;
  title: string;
  titleId: string;
  cancelLabel?: string;
  confirmLabel: string;
  onCancel: () => void;
  onConfirm: () => void;
  disabled?: boolean;
  confirmDisabled?: boolean;
  confirmClassName?: string;
  autoFocusCancel?: boolean;
  children: React.ReactNode;
}

export function NestedConfirmDialog({
  isOpen,
  title,
  titleId,
  cancelLabel = "Cancel",
  confirmLabel,
  onCancel,
  onConfirm,
  disabled = false,
  confirmDisabled = false,
  confirmClassName,
  autoFocusCancel = true,
  children,
}: NestedConfirmDialogProps): JSX.Element | null {
  const { mounted, panelOpen, backdropVisible, backdropStyle } = useStaggeredOverlay({
    isOpen,
    panelDurationMs: OVERLAY_TIMING.desktopScaleMs,
    staggerBackdrop: false,
  });

  if (!mounted) return null;

  const confirmBtnClass = confirmClassName
    ? `btn btn-primary ${confirmClassName}`
    : "btn btn-primary";

  return (
    <StaggeredOverlayRoot passThrough={!isOpen} className="nested-confirm-overlay">
      <StaggeredOverlayBackdrop
        visible={backdropVisible && isOpen}
        onClose={onCancel}
        style={backdropStyle}
        className="staggered-overlay-backdrop--deep nested-confirm-backdrop"
      />
      <StaggeredOverlayPanel
        open={panelOpen}
        className={`nested-confirm-panel staggered-overlay-panel--scale${!isOpen ? " bucket-modal-panel--closing" : ""}`}
        aria-label={title}
        role="dialog"
        aria-modal={true}
        aria-labelledby={titleId}
      >
        <h4 id={titleId} className="nested-confirm-title">
          {title}
        </h4>
        <div className="nested-confirm-content">{children}</div>
        <div className="nested-confirm-actions">
          <button
            type="button"
            className="btn btn-secondary"
            onClick={onCancel}
            disabled={disabled}
            autoFocus={autoFocusCancel}
          >
            {cancelLabel}
          </button>
          <button
            type="button"
            className={confirmBtnClass}
            onClick={onConfirm}
            disabled={disabled || confirmDisabled}
          >
            {confirmLabel}
          </button>
        </div>
      </StaggeredOverlayPanel>
    </StaggeredOverlayRoot>
  );
}
