import { useState } from "react";

import { MorpheumLogo } from "@mormlayer/components/ui/MorpheumLogo";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const FILL_PRESETS = [
  { label: "Brand green", value: "#C8F5A8" },
  { label: "Terminal brand", value: "var(--terminal-brand)" },
  { label: "White", value: "#FFFFFF" },
  { label: "Muted", value: "var(--terminal-text-muted)" },
] as const;

const SIZE_PRESETS = [
  { label: "Small", width: 40, height: 24 },
  { label: "Default", width: 58, height: 35 },
  { label: "Large", width: 87, height: 52 },
] as const;

const PADDING_PRESETS = [0, 4, 10, 16] as const;

export function MorpheumLogoPage(): JSX.Element {
  const [fill, setFill] = useState("#C8F5A8");
  const [width, setWidth] = useState(58);
  const [height, setHeight] = useState(35);
  const [padding, setPadding] = useState(10);

  return (
    <ComponentDocPage
      title="Morpheum logo"
      description="SVG wordmark for Morpheum branding. Supports custom fill, dimensions, and viewBox padding."
    >
      <DocSection
        title="Default"
        description="Default brand green fill at 58×35 with 10px padding."
      >
        <PreviewCanvas minHeight={120}>
          <MorpheumLogo />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit fill color, width, height, and inner viewBox padding."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Fill</span>
            <input
              className="uitest-input"
              value={fill}
              onChange={(e) => setFill(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Width ({width}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={32}
              max={120}
              step={2}
              value={width}
              onChange={(e) => setWidth(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Height ({height}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={20}
              max={72}
              step={2}
              value={height}
              onChange={(e) => setHeight(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Padding ({padding})</span>
            <input
              className="uitest-input"
              type="range"
              min={0}
              max={20}
              step={2}
              value={padding}
              onChange={(e) => setPadding(Number(e.target.value))}
            />
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <MorpheumLogo
            fill={fill}
            width={width}
            height={height}
            padding={padding}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection title="Fill colors" description="Common fill presets.">
        <VariantGrid columns={4}>
          {FILL_PRESETS.map((preset) => (
            <VariantTile key={preset.label} label={preset.label}>
              <MorpheumLogo fill={preset.value} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection title="Sizes" description="Scaled width and height pairs.">
        <VariantGrid columns={3}>
          {SIZE_PRESETS.map((preset) => (
            <VariantTile key={preset.label} label={preset.label}>
              <MorpheumLogo width={preset.width} height={preset.height} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection title="Padding" description="ViewBox padding in SVG units.">
        <VariantGrid columns={4}>
          {PADDING_PRESETS.map((value) => (
            <VariantTile key={value} label={`${value}px padding`}>
              <MorpheumLogo padding={value} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
