import React, { type JSX } from "react";

const EXPAND_PATHS = [
  "M6 7L12 13L18 7",
  "M17 18L7 18",
] as const;

const COLLAPSE_PATHS = [
  "M18 17L12 11L6 17",
  "M7 6L17 6",
] as const;

export type ExpandCollapseIconProps = {
  /** When true, show collapse icon; when false, show expand icon. */
  expanded: boolean;
  className?: string;
  size?: number;
  strokeWidth?: number;
  /** Rotate 180° for bottom-anchored panels (e.g. Agent Console). */
  direction?: "down" | "up";
} & Pick<React.SVGAttributes<SVGSVGElement>, "aria-hidden" | "aria-label">;

export function ExpandCollapseIcon({
  expanded,
  className,
  size = 16,
  strokeWidth = 2,
  direction = "down",
  "aria-hidden": ariaHidden = true,
  "aria-label": ariaLabel,
}: ExpandCollapseIconProps): JSX.Element {
  const paths = expanded ? COLLAPSE_PATHS : EXPAND_PATHS;

  return (
    <svg
      className={className}
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden={ariaLabel ? undefined : ariaHidden}
      aria-label={ariaLabel}
      style={direction === "up" ? { transform: "rotate(180deg)" } : undefined}
    >
      {paths.map((d) => (
        <path
          key={d}
          d={d}
          stroke="currentColor"
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      ))}
    </svg>
  );
}

export default ExpandCollapseIcon;
