import React, {
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  type ReactNode,
  type RefObject,
} from "react";

import "./stackTransition.css";

export type StackTransitionAxis = "vertical" | "horizontal";

export type StackTransitionDirection =
  | 1
  | -1
  | ((from: string, to: string) => 1 | -1);

export type StackTransitionProps = {
  focusKey: string;
  stacks: Record<string, ReactNode>;
  className?: string;
  panelClassName?: string;
  axis?: StackTransitionAxis;
  direction?: StackTransitionDirection;
  /** When true, a hidden sizer holds width from the active (destination) panel; panels stay absolute for slide animation. */
  fitContent?: boolean;
  /**
   * When set, the exiting panel keeps its menu anchored to this viewport x (px)
   * while the destination layout is reserved for the entering panel.
   */
  exitAnchorXRef?: RefObject<number | null>;
  announceChanges?: boolean;
  durationMs?: number;
};

type TransitionPhase = "idle" | "animating";

function prefersReducedMotion(): boolean {
  if (typeof window === "undefined") return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}

function resolveDirection(
  direction: StackTransitionDirection | undefined,
  from: string,
  to: string,
): 1 | -1 {
  if (direction === undefined) return 1;
  if (typeof direction === "function") return direction(from, to);
  return direction;
}

export function StackTransition({
  focusKey,
  stacks,
  className,
  panelClassName,
  axis = "vertical",
  direction: directionProp,
  fitContent = false,
  exitAnchorXRef,
  announceChanges = false,
  durationMs = 550,
}: StackTransitionProps): JSX.Element {
  const [activeKey, setActiveKey] = useState(focusKey);
  const [exitingKey, setExitingKey] = useState<string | null>(null);
  const [direction, setDirection] = useState<1 | -1>(1);
  const [phase, setPhase] = useState<TransitionPhase>("idle");
  const [enterActive, setEnterActive] = useState(false);
  const [exitActive, setExitActive] = useState(false);
  const [resolvedExitOffsetX, setResolvedExitOffsetX] = useState(0);
  const transitionIdRef = useRef(0);
  const exitPanelRef = useRef<HTMLDivElement>(null);
  const exitOffsetRef = useRef(0);

  const rootClassName = [
    "stack-transition",
    axis === "horizontal"
      ? "stack-transition--horizontal"
      : "stack-transition--vertical",
    fitContent ? "stack-transition--fit-content" : null,
    className,
  ]
    .filter(Boolean)
    .join(" ");

  const finishTransition = useCallback((transitionId: number) => {
    if (transitionIdRef.current !== transitionId) return;
    setExitingKey(null);
    setPhase("idle");
    setEnterActive(false);
    setExitActive(false);
    exitOffsetRef.current = 0;
    setResolvedExitOffsetX(0);
  }, []);

  useLayoutEffect(() => {
    if (focusKey === activeKey) return;

    const reducedMotion = prefersReducedMotion();
    const nextDirection = resolveDirection(directionProp, activeKey, focusKey);

    transitionIdRef.current += 1;
    const transitionId = transitionIdRef.current;

    if (reducedMotion) {
      setActiveKey(focusKey);
      setExitingKey(null);
      setPhase("idle");
      setEnterActive(false);
      setExitActive(false);
      exitOffsetRef.current = 0;
      setResolvedExitOffsetX(0);
      return;
    }

    setExitingKey(activeKey);
    setActiveKey(focusKey);
    setDirection(nextDirection);
    setPhase("animating");
    setEnterActive(false);
    setExitActive(false);
    exitOffsetRef.current = 0;
    setResolvedExitOffsetX(0);
  }, [focusKey, activeKey, directionProp]);

  const forward = direction === 1;
  const isAnimating = phase === "animating" && exitingKey !== null;
  const useExitAnchor = exitAnchorXRef !== undefined;

  useLayoutEffect(() => {
    if (!isAnimating || !exitingKey || !useExitAnchor) return;

    const anchor = exitAnchorXRef?.current;
    const exitLink = exitPanelRef.current?.querySelector<HTMLElement>(
      ".menubar-menu-item",
    );
    if (anchor == null || !exitLink) return;

    const visualLeft = exitLink.getBoundingClientRect().left;
    const naturalLeft = visualLeft - exitOffsetRef.current;
    const offset = anchor - naturalLeft;
    if (Math.abs(exitOffsetRef.current - offset) < 0.5) return;

    const wrapper = exitPanelRef.current?.querySelector<HTMLElement>(
      ".stack-transition__panel-offset",
    );
    if (wrapper) {
      wrapper.style.transform = `translateX(${offset}px)`;
    }
    exitOffsetRef.current = offset;
    setResolvedExitOffsetX(offset);
  }, [
    isAnimating,
    exitingKey,
    activeKey,
    enterActive,
    exitActive,
    useExitAnchor,
    exitAnchorXRef,
  ]);

  useLayoutEffect(() => {
    if (phase !== "animating" || exitingKey === null) return;

    const frame = requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        setEnterActive(true);
        setExitActive(true);
      });
    });

    return () => cancelAnimationFrame(frame);
  }, [phase, exitingKey, activeKey, direction]);

  useEffect(() => {
    if (phase !== "animating" || exitingKey === null) return;

    const transitionId = transitionIdRef.current;
    const timer = window.setTimeout(
      () => finishTransition(transitionId),
      durationMs,
    );

    return () => window.clearTimeout(timer);
  }, [phase, exitingKey, finishTransition, durationMs]);

  const handleTransitionEnd = useCallback(
    (event: React.TransitionEvent<HTMLDivElement>) => {
      if (event.propertyName !== "transform") return;
      if (phase !== "animating" || exitingKey === null) return;
      finishTransition(transitionIdRef.current);
    },
    [phase, exitingKey, finishTransition],
  );

  const sizerKey = activeKey;

  const exitPanelClass = [
    "stack-transition__panel",
    "stack-transition__panel--exit",
    panelClassName,
    exitActive
      ? forward
        ? "stack-transition__panel--exit-forward"
        : "stack-transition__panel--exit-backward"
      : "stack-transition__panel--exit-idle",
  ]
    .filter(Boolean)
    .join(" ");

  const enterPanelClass = [
    "stack-transition__panel",
    "stack-transition__panel--enter",
    panelClassName,
    !isAnimating && !fitContent && "stack-transition__panel--enter-idle",
    isAnimating && !enterActive
      ? forward
        ? "stack-transition__panel--enter-from-below"
        : "stack-transition__panel--enter-from-above"
      : null,
    isAnimating && enterActive && "stack-transition__panel--enter-active",
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <div
      className={rootClassName}
      aria-live={announceChanges ? "polite" : undefined}
    >
      {fitContent && stacks[sizerKey] !== undefined ? (
        <div className="stack-transition__sizer" aria-hidden="true">
          {stacks[sizerKey]}
        </div>
      ) : null}
      {exitingKey !== null ? (
        <div
          ref={exitPanelRef}
          className={exitPanelClass}
          onTransitionEnd={handleTransitionEnd}
          aria-hidden
        >
          {useExitAnchor ? (
            <div
              className="stack-transition__panel-offset"
              style={{ transform: `translateX(${resolvedExitOffsetX}px)` }}
            >
              {stacks[exitingKey]}
            </div>
          ) : (
            stacks[exitingKey]
          )}
        </div>
      ) : null}
      <div className={enterPanelClass}>{stacks[activeKey]}</div>
    </div>
  );
}
