import { useRef } from "react";
import { toast } from "sonner";

import { Toaster } from "@mormlayer/components/ui/Toaster";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

export function ToasterPage(): JSX.Element {
  const loadingToastId = useRef<string | number | null>(null);

  return (
    <>
      <Toaster />
      <ComponentDocPage
        title="Toaster"
        description="Sonner-based toast host styled with Morpheum terminal tokens. Use sonner toast helpers directly — not toastTask wrappers."
      >
        <DocSection
          title="Toast triggers"
          description="Click each button to fire a toast variant."
        >
          <PreviewCanvas minHeight={120}>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 12 }}>
              <button
                type="button"
                className="btn btn-primary"
                onClick={() =>
                  toast.success("Order submitted", {
                    description: "BTC-PERP limit buy queued at $67,420.",
                  })
                }
              >
                Success
              </button>
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() =>
                  toast.error("Withdrawal failed", {
                    description: "Insufficient free balance in spot wallet.",
                  })
                }
              >
                Error
              </button>
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() => {
                  loadingToastId.current = toast.loading("Syncing fleet topology...");
                }}
              >
                Loading
              </button>
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() => {
                  if (loadingToastId.current != null) {
                    toast.dismiss(loadingToastId.current);
                    loadingToastId.current = null;
                  }
                }}
              >
                Dismiss loading
              </button>
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() =>
                  toast("Agent paused", {
                    description: "Regime Detector will stop opening new positions.",
                    action: {
                      label: "Undo",
                      onClick: () => toast.success("Agent resumed"),
                    },
                  })
                }
              >
                With action
              </button>
            </div>
          </PreviewCanvas>
        </DocSection>

        <DocSection
          title="Variants"
          description="Common toast types fired independently."
        >
          <VariantGrid columns={2}>
            <VariantTile label="success">
              <button
                type="button"
                className="btn btn-primary"
                onClick={() => toast.success("Vault created")}
              >
                Show success
              </button>
            </VariantTile>
            <VariantTile label="error">
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() => toast.error("Network timeout")}
              >
                Show error
              </button>
            </VariantTile>
            <VariantTile label="loading">
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() => toast.loading("Committing mandate…")}
              >
                Show loading
              </button>
            </VariantTile>
            <VariantTile label="action">
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() =>
                  toast("Copy link ready", {
                    action: {
                      label: "Copy",
                      onClick: () => toast.success("Link copied"),
                    },
                  })
                }
              >
                Show action toast
              </button>
            </VariantTile>
          </VariantGrid>
        </DocSection>
      </ComponentDocPage>
    </>
  );
}
